from dataclasses import dataclass
from typing import Optional, Literal

EngagementStatus = Literal["applied", "partially_applied", "not_applied", "no_response"]

@dataclass
class EngagementFollowUp:
    interaction_id: str
    peer_name: str
    follow_up_date: date
    status: EngagementStatus
    result_note: Optional[str] = None

    def counts_as_engaged(self) -> bool:
        return self.status in ("applied", "partially_applied")

    def engagement_quality(self) -> str:
        if self.status == "applied" and self.result_note:
            return "HIGH"
        if self.status == "applied":
            return "MEDIUM"
        if self.status == "partially_applied":
            return "LOW"
        return "NONE"

follow_up = EngagementFollowUp(
    interaction_id="INT-2025-0412-001",
    peer_name="Alex Patel",
    follow_up_date=date(2025, 5, 12),
    status="applied",
    result_note=(
        "Used the contract extraction prompt on three internal contracts. "
        "Saved about 45 minutes per contract vs reading manually. "
        "Will use regularly for first-pass review."
    ),
)
print(follow_up.counts_as_engaged())    # True
print(follow_up.engagement_quality())  # HIGH

from dataclasses import dataclass
from typing import Optional

@dataclass
class PeerSkillRecord:
    peer_name: str
    baseline_confidence: int        # 1-5, collected at first interaction
    current_confidence: int         # 1-5, from latest follow-up
    prompt_quality_baseline: Optional[float] = None  # 1-5 rubric score, if available
    prompt_quality_current: Optional[float] = None

    def confidence_improved(self) -> bool:
        return self.current_confidence >= 4 or (
            self.baseline_confidence < 3 and self.current_confidence >= 3
        )

    def prompt_quality_improved(self) -> bool:
        if self.prompt_quality_baseline and self.prompt_quality_current:
            return (self.prompt_quality_current - self.prompt_quality_baseline) >= 1.0
        return False  # insufficient data — do not assume improvement

    def counts_as_skill_change(self) -> bool:
        return self.confidence_improved() or self.prompt_quality_improved()

    def summary(self) -> str:
        conf = f"{self.baseline_confidence} -> {self.current_confidence}"
        pq = (f"{self.prompt_quality_baseline:.1f} -> {self.prompt_quality_current:.1f}"
              if self.prompt_quality_baseline and self.prompt_quality_current else "N/A")
        changed = "YES" if self.counts_as_skill_change() else "NO"
        return f"Confidence: {conf} | Prompt quality: {pq} | Skill change: {changed}"

record = PeerSkillRecord(
    peer_name="Alex Patel",
    baseline_confidence=2,
    current_confidence=4,
    prompt_quality_baseline=2.5,
    prompt_quality_current=3.8,
)
print(record.summary())
# Confidence: 2 -> 4 | Prompt quality: 2.5 -> 3.8 | Skill change: YES
